import { ENCRYPTION_KEY } from './config';
import AES from 'react-native-aes-crypto';
import AsyncStorage from '@react-native-async-storage/async-storage';

export const encryptData = async (data) => {
    const jsonData = JSON.stringify(data);
    const iv = await AES.randomKey(16);
    const encryptedData = await AES.encrypt(jsonData, ENCRYPTION_KEY, 'aes-256-cbc', iv);
    await AsyncStorage.setItem(iv, encryptedData);
    return iv; // Return the IV for decryption
};

export const decryptData = async (iv) => {
    const encryptedData = await AsyncStorage.getItem(iv);
    if (!encryptedData) return null;
    const decryptedData = await AES.decrypt(encryptedData, ENCRYPTION_KEY, 'aes-256-cbc', iv);
    return JSON.parse(decryptedData);
};

